typedef enum {
    VARIANT_DOUBLE = 0,
    VARIANT_FLOAT = 1,
    VARIANT_NAIVE = 2
} variant_t;

static variant_t detect_variant(const char *prog) {
    if (prog) {
        if (strstr(prog, "naive") != NULL) return VARIANT_NAIVE;
        if (strstr(prog, "float") != NULL) return VARIANT_FLOAT;
        if (strstr(prog, "single") != NULL) return VARIANT_FLOAT;
        if (strstr(prog, "double") != NULL) return VARIANT_DOUBLE;
    }
    return VARIANT_DOUBLE;
}

long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

double elapsed_time(long long start_time, long long end_time) {
    return (double)(end_time - start_time) / (1000.0 * 1000.0);
}

double randu_double(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double)M));
}

double randn_double(int *seed, int index) {
    double u = randu_double(seed, index);
    double v = randu_double(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

float randu_float(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((float)M));
}

float randn_float(int *seed, int index) {
